	private static String runNodeScript(String script) throws Exception {
		Path scriptPath = Path.of("src/main/webapp/scripts/query-trace-player.js").toAbsolutePath();
		Process process = new ProcessBuilder("node", "-e", script, scriptPath.toString())
				.redirectErrorStream(true)
				.start();
		ByteArrayOutputStream output = new ByteArrayOutputStream();
		process.getInputStream().transferTo(output);

		assertThat(process.waitFor()).isZero();
		return output.toString(StandardCharsets.UTF_8);
	}
